// ---------------------------------------------------------------------------
// MAT-V3-01 — PBR texture application helpers
// ---------------------------------------------------------------------------

/**
 * Apply PBR map slots from a MaterialElem onto an existing MeshStandardMaterial.
 * imageAssetsById maps imageAssetId → THREE.Texture (caller loads textures).
 * In plan/elevation views, PBR maps are ignored — only albedoColor / hatch apply.
 */
export function applyPbrMaps(
  mat: THREE.MeshStandardMaterial,
  materialElem: MaterialElem,
  imageAssetsById: Record<string, THREE.Texture>,
): void {
  if (materialElem.albedoMapId) {
    const tex = imageAssetsById[materialElem.albedoMapId];
    if (tex) mat.map = tex;
  }
  if (materialElem.normalMapId) {
    const tex = imageAssetsById[materialElem.normalMapId];
    if (tex) mat.normalMap = tex;
  }
  if (materialElem.roughnessMapId) {
    const tex = imageAssetsById[materialElem.roughnessMapId];
    if (tex) mat.roughnessMap = tex;
  }
  if (materialElem.metallicMapId) {
    const tex = imageAssetsById[materialElem.metallicMapId];
    if (tex) mat.metalnessMap = tex;
  }
  const uvScale = materialElem.uvScaleMm ?? { uMm: 1000, vMm: 1000 };
  if (mat.map) {
    mat.map.repeat.set(1 / uvScale.uMm, 1 / uvScale.vMm);
    mat.map.wrapS = THREE.RepeatWrapping;
    mat.map.wrapT = THREE.RepeatWrapping;
  }
  mat.needsUpdate = true;
}

/**
 * Build a thin plane mesh for a DecalElem hosted on a parent surface.
 * Renders only in 3D; invisible in plan/elevation.
 */
export function buildDecalMesh(
  decal: DecalElem,
  parentMesh: THREE.Mesh,
  imageAssetsById: Record<string, THREE.Texture>,
): THREE.Mesh | null {
  const tex = imageAssetsById[decal.imageAssetId];
  if (!tex) return null;

  const { u0, v0, u1, v1 } = decal.uvRect;
  const uWidth = u1 - u0;
  const vHeight = v1 - v0;

  const geom = new THREE.PlaneGeometry(uWidth, vHeight);
  const mat = new THREE.MeshBasicMaterial({
    map: tex,
    transparent: true,
    opacity: decal.opacity ?? 1.0,
    depthWrite: false,
    polygonOffset: true,
    polygonOffsetFactor: -1,
  });

  const mesh = new THREE.Mesh(geom, mat);
  mesh.userData.bimPickId = decal.id;
  mesh.userData.isDecal = true;

  // Position at the UV rect centre on the parent surface
  const uCenter = u0 + uWidth / 2;
  const vCenter = v0 + vHeight / 2;

  switch (decal.parentSurface) {
    case 'front':
      mesh.position.set(uCenter, vCenter, 0.1);
      break;
    case 'back':
      mesh.rotation.y = Math.PI;
      mesh.position.set(-uCenter, vCenter, -0.1);
      break;
    case 'top':
      mesh.rotation.x = -Math.PI / 2;
      mesh.position.set(uCenter, 0.1, -vCenter);
      break;
    default:
      mesh.position.set(uCenter, vCenter, 0.1);
  }

  parentMesh.add(mesh);
  return mesh;
}

